from confluent_kafka import Producer

conf = {'bootstrap.servers': 'kafka-broker:9092'}
p = Producer(**conf)

def delivery_report(err, msg):
    if err is not None:
        print('Delivery failed: {}'.format(err))
    else:
        print('Delivered message to {} [{}]'.format(msg.topic(), msg.partition()))

# send 1M simple events (example loop)
for i in range(1000000):
    p.produce('events_topic', key=str(i % 1000), value='{"evt": %d}' % i, callback=delivery_report)
    if i % 10000 == 0:
        p.flush()

p.flush()

